	<script>
		document.addEventListener('DOMContentLoaded', (event) => {
			const video = document.getElementById('fco-intro-video');
			const playButton = document.getElementById('fco-intro-video-play');

			let videoURL = null;
			let videoLoading = false;

			playButton.addEventListener('click', () => {
				// Only fetch video when play button is clicked
				if (!videoURL && !videoLoading) {
					videoLoading = true;
					playButton.style.cursor = 'wait';
					
					fetch('https://res.cloudinary.com/djekzslu5/video/upload/v1729596154/FCO_Intro_xtako3.mp4')
					.then(response => response.blob())
					.then(blob => {
						videoURL = URL.createObjectURL(blob);
						videoLoading = false;
						playButton.style.cursor = 'pointer';
						
						// Now that video is loaded, hide button and play
						playButton.style.display = 'none';
						video.style.display = 'block';
						video.src = videoURL;
						video.play();
					})
					.catch(error => {
						console.error('Error fetching video:', error);
						videoLoading = false;
						playButton.style.cursor = 'pointer';
						alert('Error loading video. Please try again.');
					});
				} else if (videoURL) {
					// Video already loaded, just play it
					playButton.style.display = 'none';
					video.style.display = 'block';
					if (!video.src) {
						video.src = videoURL;
					}
					video.play();
				}
			});
		});
	</script>

    

